import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { FaUsers, FaMoneyBillWave, FaSyncAlt, FaBuilding } from 'react-icons/fa';

function Navbar() {
  const location = useLocation();

  const isActive = (path) => {
    return location.pathname.startsWith(path);
  };

  return (
    <nav className="navbar">
      <div className="navbar-content">
        <Link to="/" className="navbar-brand">
          <FaBuilding size={28} />
          <h1>HR & Payroll Dashboard</h1>
        </Link>
        <div className="navbar-links">
          <Link 
            to="/employees" 
            className={`nav-link ${isActive('/employees') ? 'active' : ''}`}
          >
            <FaUsers />
            <span>Employees</span>
          </Link>
          <Link 
            to="/payroll" 
            className={`nav-link ${isActive('/payroll') ? 'active' : ''}`}
          >
            <FaMoneyBillWave />
            <span>Payroll</span>
          </Link>
          <Link 
            to="/sync" 
            className={`nav-link ${isActive('/sync') ? 'active' : ''}`}
          >
            <FaSyncAlt />
            <span>Sync</span>
          </Link>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
